SELECT category_id, COUNT(*) AS nomination_count
FROM nominations
WHERE category_id = 1;

SELECT COUNT(ceremony_id) AS number_of_ceremonies_sponsored
FROM ceremony_sponsorship
WHERE sponsor_id = 1;

SELECT festival_name, festival_description, festival_start_date
FROM festivals
ORDER BY festival_start_date ASC;

SELECT work_title
FROM works
ORDER BY work_title ASC;
